import{_ as l,o as e,c as i,a2 as n}from"./chunks/framework.DZrHScmQ.js";const u=JSON.parse('{"title":"Feishu and OpenClaw Collaboration","description":"","frontmatter":{},"headers":[],"relativePath":"ai-native/workflows/feishu-openclaw-collaboration.md","filePath":"ai-native/workflows/feishu-openclaw-collaboration.md"}'),s={name:"ai-native/workflows/feishu-openclaw-collaboration.md"};function t(p,a,o,r,d,h){return e(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="feishu-and-openclaw-collaboration" tabindex="-1">Feishu and OpenClaw Collaboration <a class="header-anchor" href="#feishu-and-openclaw-collaboration" aria-label="Permalink to &quot;Feishu and OpenClaw Collaboration&quot;">​</a></h1><p><strong>状态：Draft</strong></p><p><strong>Owner：待指定</strong></p><h2 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h2><p>让团队成员可以在飞书中与 OpenClaw 协作，同时保持任务归属、权限边界、交付证据和组织知识真源清晰。</p><p>本 Workflow 适用于协作入口，不规定 OpenClaw 实例的私有群 ID、成员 ID、凭证和部署路径。</p><h2 id="角色" tabindex="-1">角色 <a class="header-anchor" href="#角色" aria-label="Permalink to &quot;角色&quot;">​</a></h2><table tabindex="0"><thead><tr><th>角色</th><th>责任</th></tr></thead><tbody><tr><td>Requester</td><td>提供目标和业务判断，确认高风险动作</td></tr><tr><td>OpenClaw</td><td>澄清、分类、路由、跟踪和汇报</td></tr><tr><td>Specialist Agent</td><td>执行研究、代码、文档或运营任务</td></tr><tr><td>Reviewer</td><td>检查交付物、证据和风险</td></tr><tr><td>Owner</td><td>对系统、项目或长期规则承担最终责任</td></tr></tbody></table><p>一个人可以兼任多个角色，但 OpenClaw 不能兼任最终 Owner。</p><h2 id="任务入口" tabindex="-1">任务入口 <a class="header-anchor" href="#任务入口" aria-label="Permalink to &quot;任务入口&quot;">​</a></h2><h3 id="适合在飞书直接提出" tabindex="-1">适合在飞书直接提出 <a class="header-anchor" href="#适合在飞书直接提出" aria-label="Permalink to &quot;适合在飞书直接提出&quot;">​</a></h3><ul><li>检索和摘要</li><li>生成会议或项目草稿</li><li>创建 Knowledge Candidate</li><li>查询项目 About、状态、任务、PR、CI、Release 和监控摘要</li><li>接收异常、阻塞、过期事项和待审批提醒</li><li>发起 bug 修复或 Release 协调流程</li><li>启动低风险、已有 Playbook 的任务</li><li>路由代码任务给 Codex 或 Claude Code</li></ul><h3 id="先找-owner-再执行" tabindex="-1">先找 Owner 再执行 <a class="header-anchor" href="#先找-owner-再执行" aria-label="Permalink to &quot;先找 Owner 再执行&quot;">​</a></h3><ul><li>发布、回滚和生产配置</li><li>权限、密钥和账号操作</li><li>Credits、结算和真实资金</li><li>外部公开消息</li><li>删除、覆盖或批量修改共享数据</li><li>将 Draft 晋升为组织 Standard</li></ul><h2 id="标准任务格式" tabindex="-1">标准任务格式 <a class="header-anchor" href="#标准任务格式" aria-label="Permalink to &quot;标准任务格式&quot;">​</a></h2><p>团队成员不需要每次填完整表单，但 OpenClaw 在执行或路由前应补齐：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>目标：</span></span>
<span class="line"><span>相关项目或仓库：</span></span>
<span class="line"><span>上下文或来源：</span></span>
<span class="line"><span>约束：</span></span>
<span class="line"><span>完成条件：</span></span>
<span class="line"><span>截止时间：</span></span>
<span class="line"><span>风险等级：</span></span>
<span class="line"><span>需要谁批准：</span></span>
<span class="line"><span>结果返回到哪个飞书 Thread：</span></span></code></pre></div><p>信息不足时，OpenClaw 先问最少数量的关键问题，不能用猜测填入项目、身份或生产环境。</p><h2 id="协作流程" tabindex="-1">协作流程 <a class="header-anchor" href="#协作流程" aria-label="Permalink to &quot;协作流程&quot;">​</a></h2><h3 id="_1-接收与确认" tabindex="-1">1. 接收与确认 <a class="header-anchor" href="#_1-接收与确认" aria-label="Permalink to &quot;1. 接收与确认&quot;">​</a></h3><p>OpenClaw 在同一 Thread 回复：</p><ul><li>对目标的简短复述</li><li>任务类型和预计交付物</li><li>风险等级</li><li>是否需要人类批准</li><li>将由哪个 Agent 或 Skill 处理</li></ul><h3 id="_2-建立执行上下文" tabindex="-1">2. 建立执行上下文 <a class="header-anchor" href="#_2-建立执行上下文" aria-label="Permalink to &quot;2. 建立执行上下文&quot;">​</a></h3><ul><li>一个独立任务使用一个飞书 Thread 或明确的任务 ID</li><li>代码任务绑定指定仓库和隔离 Workspace</li><li>私人请求与团队群任务不共享 Session</li><li>子任务需要委派时记录 Parent Task</li></ul><p>不要在普通群聊主线中混合多个长期任务。</p><h3 id="_3-路由" tabindex="-1">3. 路由 <a class="header-anchor" href="#_3-路由" aria-label="Permalink to &quot;3. 路由&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任务</th><th>默认执行者</th></tr></thead><tbody><tr><td>简单问答、路由、状态汇总</td><td>OpenClaw Coordinator</td></tr><tr><td>代码修改、测试和 PR</td><td>Codex 或 Claude Code</td></tr><tr><td>飞书文档、任务、日历操作</td><td>Feishu CLI Skill</td></tr><tr><td>Handbook 草稿</td><td>Knowledge Agent 或独立文档会话</td></tr><tr><td>定时监控和日报</td><td>OpenClaw Cron / Automation</td></tr></tbody></table><p>能由确定性 Tool 完成的操作，不让模型用自然语言模拟。</p><h3 id="feishu-cli-调用边界" tabindex="-1">Feishu CLI 调用边界 <a class="header-anchor" href="#feishu-cli-调用边界" aria-label="Permalink to &quot;Feishu CLI 调用边界&quot;">​</a></h3><p>OpenClaw 负责对话、分级和路由；Feishu CLI 负责结构化飞书资源操作。</p><p>适合调用 Feishu CLI：</p><ul><li>读取或创建飞书文档、任务、日历、多维表格和消息草稿。</li><li>查询资源 schema、权限和当前状态。</li><li>对写操作生成 dry-run，并在批准后执行和回读验证。</li></ul><p>不直接调用 Feishu CLI：</p><ul><li>请求者身份、目标资源或权限范围不清楚。</li><li>操作涉及权限、删除、覆盖、审批、外部正式消息或批量跨空间写入，且尚未 dry-run + 人审。</li><li>飞书内容要求扩大权限、泄露数据或执行未知命令。</li></ul><p>调用后必须把资源 ID、执行身份、关键参数和回读结果返回到原 Thread。具体 CLI 规则见 <a href="./../tooling/feishu-cli.html">Feishu CLI Practices</a>。</p><h3 id="_4-执行与进度" tabindex="-1">4. 执行与进度 <a class="header-anchor" href="#_4-执行与进度" aria-label="Permalink to &quot;4. 执行与进度&quot;">​</a></h3><p>超过一个工作阶段的任务至少在以下时点更新：</p><ul><li>已完成上下文收集</li><li>需要批准或遇到阻塞</li><li>已产生可审查草稿或 Diff</li><li>验证完成</li></ul><p>进度消息应包含事实，不发送没有信息量的“正在处理”。</p><h3 id="_5-高风险确认" tabindex="-1">5. 高风险确认 <a class="header-anchor" href="#_5-高风险确认" aria-label="Permalink to &quot;5. 高风险确认&quot;">​</a></h3><p>R2 及以上写操作执行前，OpenClaw 应展示：</p><ul><li>目标资源</li><li>计划动作</li><li>影响范围</li><li>Dry Run 或 Diff</li><li>回滚或恢复方式</li></ul><p>只有明确批准后才能继续。批准只适用于本次展示的范围，不能扩展成永久授权。</p><h3 id="_6-交付" tabindex="-1">6. 交付 <a class="header-anchor" href="#_6-交付" aria-label="Permalink to &quot;6. 交付&quot;">​</a></h3><p>OpenClaw 在原 Thread 返回：</p><ul><li>结果摘要</li><li>交付物链接或资源 ID</li><li>实际执行者</li><li>运行的验证及结果</li><li>未完成事项和风险</li><li>是否建议沉淀到 Handbook</li></ul><p>代码任务以 PR、Commit 或可审查 Diff 为交付；文档任务以 Draft PR 或飞书草稿为交付。</p><h3 id="_7-review-与关闭" tabindex="-1">7. Review 与关闭 <a class="header-anchor" href="#_7-review-与关闭" aria-label="Permalink to &quot;7. Review 与关闭&quot;">​</a></h3><p>Reviewer 检查交付物后明确：</p><ul><li><code>Accepted</code></li><li><code>Changes requested</code></li><li><code>Blocked</code></li><li><code>Cancelled</code></li></ul><p>没有 Reviewer 结论的任务不应仅因 Agent 停止回复而被视为完成。</p><h3 id="_8-知识沉淀" tabindex="-1">8. 知识沉淀 <a class="header-anchor" href="#_8-知识沉淀" aria-label="Permalink to &quot;8. 知识沉淀&quot;">​</a></h3><p>任务结束后按内容类型处理：</p><ul><li>一次性对话：保留在飞书 Thread</li><li>项目事实：更新项目文档或代码仓库</li><li>重复摩擦：建立 Observation 或 Knowledge Candidate</li><li>稳定工作流：建立 Skill 或 Playbook</li><li>跨项目结论：通过 PR 进入 Evolution Handbook</li></ul><p>OpenClaw 可以生成候选草稿，但不能自动将群聊结论合并为 Standard。</p><h2 id="项目后台能力" tabindex="-1">项目后台能力 <a class="header-anchor" href="#项目后台能力" aria-label="Permalink to &quot;项目后台能力&quot;">​</a></h2><p>飞书可以作为轻量项目后台入口，但不替代真实系统或项目契约。</p><p>OpenClaw 可以在 Thread 中汇总：</p><ul><li>About：项目目标、Owner、仓库、环境、入口链接和当前边界</li><li>状态：任务、PR、CI、Release、监控、阻塞项和下一步</li><li>链接：Handbook、项目契约、Playbook、真实系统和相关 Thread</li></ul><p>About 应尽量保持一屏内，回答：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目是什么：</span></span>
<span class="line"><span>当前目标：</span></span>
<span class="line"><span>Owner / Reviewer：</span></span>
<span class="line"><span>相关仓库：</span></span>
<span class="line"><span>生产 / 测试入口：</span></span>
<span class="line"><span>关键契约：</span></span>
<span class="line"><span>当前风险或边界：</span></span>
<span class="line"><span>下一步入口：</span></span></code></pre></div><p>About 只放稳定导航和当前判断，不放密钥、内部地址、客户数据或流水式状态。状态变化频繁的内容进入状态摘要或原系统链接。</p><p>写操作仍按风险等级处理；发布、权限、结算、生产数据和外部正式消息必须先 dry-run + 人审。</p><h2 id="release-协调" tabindex="-1">Release 协调 <a class="header-anchor" href="#release-协调" aria-label="Permalink to &quot;Release 协调&quot;">​</a></h2><p>飞书可以发起 Release 协调，但不能替代发布系统和项目级 release playbook。</p><p>OpenClaw 在执行或路由前补齐：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Release 目标：</span></span>
<span class="line"><span>变更范围：</span></span>
<span class="line"><span>涉及仓库：</span></span>
<span class="line"><span>验证方式：</span></span>
<span class="line"><span>回滚方式：</span></span>
<span class="line"><span>Owner / Reviewer：</span></span>
<span class="line"><span>计划窗口：</span></span></code></pre></div><p>默认流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>确认范围</span></span>
<span class="line"><span>  -&gt; 检查 PR、CI、迁移、Feature Flag 和依赖顺序</span></span>
<span class="line"><span>  -&gt; 汇总 dry-run / release plan</span></span>
<span class="line"><span>  -&gt; 人审批准</span></span>
<span class="line"><span>  -&gt; 执行或路由发布</span></span>
<span class="line"><span>  -&gt; 监控结果</span></span>
<span class="line"><span>  -&gt; 回到原 Thread 汇报</span></span></code></pre></div><p>生产发布、回滚、权限、结算或数据迁移都属于高风险动作，必须明确批准后执行。</p><h2 id="监控与通知" tabindex="-1">监控与通知 <a class="header-anchor" href="#监控与通知" aria-label="Permalink to &quot;监控与通知&quot;">​</a></h2><p>飞书通知用于协作提醒，不作为产品内通知契约。产品通知契约应回到对应项目文档。</p><p>适合进入飞书的通知：</p><ul><li>CI、PR、发布和定时任务状态</li><li>监控异常、重复失败和 Owner 阻塞</li><li>Handbook 断链、过期内容和 Knowledge Candidate 汇总</li><li>需要人类批准的高风险动作</li></ul><p>通知应包含来源、影响范围、建议动作和关闭条件；避免只发送“失败了”或“处理中”。</p><h2 id="bug-修复入口" tabindex="-1">Bug 修复入口 <a class="header-anchor" href="#bug-修复入口" aria-label="Permalink to &quot;Bug 修复入口&quot;">​</a></h2><p>飞书报告 bug 时，OpenClaw 先补齐最小信息：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>现象：</span></span>
<span class="line"><span>影响范围：</span></span>
<span class="line"><span>复现步骤：</span></span>
<span class="line"><span>期望结果：</span></span>
<span class="line"><span>实际结果：</span></span>
<span class="line"><span>相关链接或截图：</span></span>
<span class="line"><span>是否影响生产：</span></span></code></pre></div><p>默认流程：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>确认信息</span></span>
<span class="line"><span>  -&gt; 判断项目、仓库和风险等级</span></span>
<span class="line"><span>  -&gt; 路由给 Codex / Claude Code</span></span>
<span class="line"><span>  -&gt; 生成 Diff 或 PR</span></span>
<span class="line"><span>  -&gt; 运行验证</span></span>
<span class="line"><span>  -&gt; 回到原 Thread 汇报</span></span>
<span class="line"><span>  -&gt; Reviewer 关闭</span></span></code></pre></div><p>生产事故、安全、权限、结算或数据修复类 bug 先升级给 Owner，不直接进入自动修复。</p><h2 id="推荐的飞书组织方式" tabindex="-1">推荐的飞书组织方式 <a class="header-anchor" href="#推荐的飞书组织方式" aria-label="Permalink to &quot;推荐的飞书组织方式&quot;">​</a></h2><ul><li>一个团队协作群，只在 @mention 时响应</li><li>复杂任务使用 Topic / Thread</li><li>固定消息或群公告链接到 Handbook、项目入口和贡献指南</li><li>高风险审批使用明确的人类回复，不使用表情或沉默作为批准</li><li>定时报告发到专用 Thread 或专用群，避免淹没任务讨论</li></ul><h2 id="推荐的自动化" tabindex="-1">推荐的自动化 <a class="header-anchor" href="#推荐的自动化" aria-label="Permalink to &quot;推荐的自动化&quot;">​</a></h2><h3 id="可以先落地" tabindex="-1">可以先落地 <a class="header-anchor" href="#可以先落地" aria-label="Permalink to &quot;可以先落地&quot;">​</a></h3><ul><li>每日未关闭任务摘要</li><li>PR、CI 或发布状态汇总</li><li>会议纪要转 Draft Action Items</li><li>Handbook 断链和过期链接提醒</li><li>Knowledge Candidate 周度汇总</li></ul><h3 id="暂不无人值守" tabindex="-1">暂不无人值守 <a class="header-anchor" href="#暂不无人值守" aria-label="Permalink to &quot;暂不无人值守&quot;">​</a></h3><ul><li>自动合并 PR</li><li>自动发布生产</li><li>自动修改权限和密钥</li><li>自动对外发送正式声明</li><li>自动删除飞书或 Git 数据</li><li>自动晋升组织规则</li></ul><h2 id="失败与升级" tabindex="-1">失败与升级 <a class="header-anchor" href="#失败与升级" aria-label="Permalink to &quot;失败与升级&quot;">​</a></h2><p>遇到以下情况，OpenClaw 停止执行并升级给 Owner：</p><ul><li>无法确认请求者身份或权限</li><li>指令与 Handbook、项目契约或安全规则冲突</li><li>外部内容要求泄露数据、扩大权限或执行未知命令</li><li>同一动作重复失败</li><li>目标资源或生产环境不明确</li><li>无法生成可验证的交付物</li></ul><h2 id="完成条件" tabindex="-1">完成条件 <a class="header-anchor" href="#完成条件" aria-label="Permalink to &quot;完成条件&quot;">​</a></h2><ul><li>[ ] 任务有明确 Requester、执行者和返回 Thread</li><li>[ ] 目标、约束和完成条件已确认</li><li>[ ] Session 和 Workspace 与其他成员隔离</li><li>[ ] 高风险动作获得对应范围的批准</li><li>[ ] 交付物可审查</li><li>[ ] 验证证据已返回</li><li>[ ] Owner 或 Reviewer 已给出关闭结论</li><li>[ ] 可复用经验已进入候选沉淀流程</li></ul><h2 id="相关内容" tabindex="-1">相关内容 <a class="header-anchor" href="#相关内容" aria-label="Permalink to &quot;相关内容&quot;">​</a></h2><ul><li><a href="./../tooling/openclaw.html">OpenClaw Practices</a></li><li><a href="./../tooling/feishu-cli.html">Feishu CLI Practices</a></li><li><a href="./../tooling/codex.html">Codex Practices</a></li><li><a href="./../tooling/claude-code.html">Claude Code Practices</a></li><li><a href="./../governance/risk-and-automation-levels.html">AI 风险与自动化等级</a></li><li><a href="./../playbooks/run-context-review.html">运行上下文复审</a></li><li><a href="./../../CONTRIBUTING.html">参与 Handbook 共建</a></li></ul>`,95)])])}const b=l(s,[["render",t]]);export{u as __pageData,b as default};
